const body = $input.first().json.body || $input.first().json;
const call = body.call || body;

const agentId = call.agent_id || '';
const callId = call.call_id || '';
const transcript = call.transcript || '';
const durationMs = call.duration_ms || 0;
const callStatus = call.call_status || '';
const fromNumber = call.from_number || '';
const toNumber = call.to_number || '';
const disconnectionReason = call.disconnection_reason || '';
const analysis = call.call_analysis || {};

return {
  agent_id: agentId,
  call_id: callId,
  transcript: transcript,
  from_number: fromNumber,
  to_number: toNumber,
  duration_seconds: Math.round(durationMs / 1000),
  call_status: callStatus,
  disconnection_reason: disconnectionReason,
  call_analysis: analysis,
  call_timestamp: new Date().toISOString()
};

const callData = $('Extract Call Data').first().json;
const rawInput = $input.first().json;

// n8n httpRequest with Supabase REST: when Supabase returns [{...}], 
// n8n passes the single object as the item json directly.
// When Supabase returns [], n8n passes nothing (0 items) and this node won't run.
// But with neverError, it may pass the empty array or an error object.

let client = rawInput;

// Check if this is a Supabase error or empty response
if (!client || !client.company_name) {
  // Could be error object from Supabase
  if (client && client.code) {
    console.log('Supabase error:', client.code, client.message);
  }
  return {
    ...callData,
    company_name: 'Unknown Company',
    client_email: '',
    lead_email: '',
    lead_phone: '',
    lead_contact_method: 'Both',
    notification_email_2: '',
    notification_email_3: '',
    notification_sms_2: '',
    notification_sms_3: '',
    timezone: 'America/Chicago',
    calendar_platform: '',
    crm_platform: '',
    _client_found: false
  };
}

return {
  ...callData,
  company_name: client.company_name || '',
  client_email: client.client_email || '',
  lead_email: client.lead_email || '',
  lead_phone: client.lead_phone || '',
  lead_contact_method: client.lead_contact_method || 'Both',
  notification_email_2: client.notification_email_2 || '',
  notification_email_3: client.notification_email_3 || '',
  notification_sms_2: client.notification_sms_2 || '',
  notification_sms_3: client.notification_sms_3 || '',
  timezone: client.timezone || 'America/Chicago',
  calendar_platform: client.calendar_platform || '',
  crm_platform: client.crm_platform || '',
  _client_found: true
};

