  console.log(`[EMAIL] Sent to ${recipients.join(', ')}: ${emailSubject}`);
  return { ...d, _email_sent: true, _email_recipients: recipients };
} catch (e) {
  console.log('[EMAIL] Send failed:', e.message);
  return { ...d, _email_sent: false, _reason: e.message };
}

const d = $input.first().json;
const smsText = d.sms_text || '';
const leadPhone = d.lead_phone || '';
const sms2 = d.notification_sms_2 || '';
const sms3 = d.notification_sms_3 || '';

if (!leadPhone || !smsText) {
  console.log('[SMS] No phone or text — skipping');
  return { ...d, _sms_sent: false, _reason: 'No phone number or text' };
}

// Build recipient list
const recipients = [leadPhone];
if (sms2) recipients.push(sms2);
if (sms3) recipients.push(sms3);

const TELNYX_KEY = $vars.TELNYX_API_KEY || '';
const TELNYX_FROM = $vars.TELNYX_FROM_NUMBER || '';

// ── SMS DISABLED UNTIL TELNYX IS CONFIGURED ──
// When ready: set TELNYX_API_KEY and TELNYX_FROM_NUMBER in n8n Variables
const SMS_ENABLED = false; // ← Change to true when Telnyx is ready

if (!SMS_ENABLED || !TELNYX_KEY || !TELNYX_FROM) {
  console.log(`[SMS] Disabled or not configured — would send to: ${recipients.join(', ')}`);
  console.log(`[SMS] Text: ${smsText.substring(0, 100)}`);
  return { ...d, _sms_sent: false, _reason: 'SMS disabled — awaiting Telnyx configuration' };
}

// Send to each recipient
let sentCount = 0;
for (const phone of recipients) {
  try {
    await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://api.telnyx.com/v2/messages',
      headers: {
        'Authorization': 'Bearer ' + TELNYX_KEY,
        'Content-Type': 'application/json'
      },
      body: {
        from: TELNYX_FROM,
        to: phone,
        text: smsText
      },
      json: true
    });
    sentCount++;
  } catch (e) {
    console.log(`[SMS] Failed to send to ${phone}:`, e.message);
  }
}

console.log(`[SMS] Sent ${sentCount}/${recipients.length} messages`);
return { ...d, _sms_sent: sentCount > 0, _sms_count: sentCount };

const d = $input.first().json;

// ── Error condition detection ──────────────────────────────────────────────
const disconnReason = (d.disconnection_reason || '').toLowerCase();
const callStatus    = (d.call_status || '').toLowerCase();
const transferAttempted = d.transfer_attempted || false;
const transferSuccess   = d.transfer_success;  // true | false | null
const clientFound   = d._client_found !== false; // false = Supabase lookup failed
const geocodeStatus = (d.geocode_status || '').toLowerCase();
const gptFailed     = d._gpt_failed || false;

// Retell disconnection reasons that indicate a problem
const TRANSFER_FAIL_REASONS = [
  'dial_failed', 'dial_busy', 'dial_no_answer',
  'dial_no_answer_voicemail', 'transfer_failed',
  'transfer_to_human_failed', 'voicemail',
  'inactivity', 'machine_detected'
];

const HARD_ERROR_REASONS = [
  'error', 'error_inbound_webhook', 'error_llm_websocket',
  'error_frontend_websocket', 'error_no_answer_human_response',
  'concurrency_limit_reached', 'server_error',
  'rate_limit_error', 'webhook_failed'
];

const SUSPICIOUS_REASONS = [
  'abandoned', 'call_ended_early'
];

// Evaluate all error conditions
const errors = [];

// 1. Hard system errors
if (HARD_ERROR_REASONS.some(r => disconnReason.includes(r))) {
  errors.push({ type: 'SYSTEM_ERROR', detail: `disconnection_reason: ${d.disconnection_reason}` });
}
if (callStatus === 'error' || callStatus === 'failed') {
  errors.push({ type: 'CALL_STATUS_ERROR', detail: `call_status: ${d.call_status}` });
}

// 2. Transfer failures
if (TRANSFER_FAIL_REASONS.some(r => disconnReason.includes(r))) {
  errors.push({ type: 'TRANSFER_FAILED', detail: `disconnection_reason: ${d.disconnection_reason}` });
}
if (transferAttempted && transferSuccess === false) {
  errors.push({ type: 'TRANSFER_UNSUCCESSFUL', detail: 'Transfer was attempted but did not succeed' });
}

// 3. Suspicious / abnormal endings
if (SUSPICIOUS_REASONS.some(r => disconnReason.includes(r))) {
  errors.push({ type: 'ABNORMAL_ENDING', detail: `disconnection_reason: ${d.disconnection_reason}` });
}

// 4. Client lookup failure (agent fired but client not in Supabase)
if (!clientFound) {
  errors.push({ type: 'CLIENT_NOT_FOUND', detail: `agent_id: ${d.agent_id} not found in Supabase` });
}

// 5. Very short calls (< 8 seconds, likely system fault not human hangup)
const dur = d.duration_seconds || 0;
if (dur > 0 && dur < 8) {
  errors.push({ type: 'CALL_TOO_SHORT', detail: `Duration: ${dur}s — likely failed connection` });
}

// 6. Geocode error (not blocking but worth knowing)
if (geocodeStatus === 'error') {
  errors.push({ type: 'GEOCODE_ERROR', detail: 'Address geocoding failed for this call' });
}

// 7. GPT analysis failed
if (gptFailed) {
  errors.push({ type: 'GPT_ANALYSIS_FAILED', detail: 'AI transcript analysis failed — call logged with raw data only' });
}

// ── If no errors, exit silently ────────────────────────────────────────────
if (errors.length === 0) {
  return [{ json: { ...d, _alert_sent: false, _alert_reason: 'no_errors' } }];
}

// ── Build alert email ──────────────────────────────────────────────────────
const primaryError = errors[0];
const errorCount = errors.length;
const isCritical = ['SYSTEM_ERROR','CALL_STATUS_ERROR','CLIENT_NOT_FOUND'].includes(primaryError.type);
const accentColour = isCritical ? '#EF4444' : '#F59E0B';
const tierLabel = d.company_name ? ` — ${d.company_name}` : '';
