// Merge GPT analysis with original call data from Check Repeat Caller
const gptOutput = $input.first().json;
const originalData = $('Check Repeat Caller').first().json;

// Parse GPT content - it returns nested JSON object
let gptData = {};
try {
  const content = gptOutput.message?.content || gptOutput.content || '';
  if (typeof content === 'string' && content.trim().startsWith('{')) {
    const parsed = JSON.parse(content);
    // Flatten the nested GPT structure
    gptData = {
      ...(parsed['CALLER INFORMATION'] || {}),
      ...(parsed['CALL CLASSIFICATION'] || {}),
      ...(parsed['BOOKING DATA'] || {}),
      ...(parsed['LEAD QUALIFICATION'] || {}),
      ...(parsed['ADDITIONAL'] || {}),
    };
  }
} catch(e) {
  // GPT parsing failed — use original call_analysis data
}

// Merge: original data takes priority for call metadata, GPT data fills analysis fields
const merged = {
  // Core call identifiers from original (never from GPT)
  call_id: originalData.call_id,
  agent_id: originalData.agent_id,
  company_name: originalData.company_name,
  client_email: originalData.client_email,
  lead_email: originalData.lead_email,
  lead_phone: originalData.lead_phone,
  lead_contact_method: originalData.lead_contact_method,
  notification_email_2: originalData.notification_email_2,
  notification_email_3: originalData.notification_email_3,
  notification_sms_2: originalData.notification_sms_2,
  notification_sms_3: originalData.notification_sms_3,
  timezone: originalData.timezone,
  calendar_platform: originalData.calendar_platform,
  crm_platform: originalData.crm_platform,
  from_number: originalData.from_number,
  to_number: originalData.to_number,
  transcript: originalData.transcript,
  duration_seconds: originalData.duration_seconds,
  disconnection_reason: originalData.disconnection_reason,
  call_timestamp: originalData.call_timestamp,
  is_repeat_caller: originalData.is_repeat_caller || false,
  repeat_call_count: originalData.repeat_call_count || 0,
  _client_found: originalData._client_found,

  // Analysis fields from GPT (fall back to call_analysis if GPT failed)
  caller_name: gptData.caller_name || originalData.call_analysis?.custom_analysis_data?.caller_name || '',
  caller_phone: gptData.caller_phone || originalData.call_analysis?.custom_analysis_data?.caller_phone || originalData.from_number || '',
  caller_address: gptData.caller_address || originalData.call_analysis?.custom_analysis_data?.caller_address || '',
  caller_email: gptData.caller_email || originalData.call_analysis?.custom_analysis_data?.caller_email || '',
  caller_sentiment: gptData.caller_sentiment || originalData.call_analysis?.user_sentiment || '',
  call_type: gptData.call_type || originalData.call_analysis?.custom_analysis_data?.call_type || '',
  service_requested: gptData.service_requested || originalData.call_analysis?.custom_analysis_data?.service_requested || '',
  urgency: gptData.urgency || originalData.call_analysis?.custom_analysis_data?.urgency || '',
  job_type: gptData.job_type || originalData.call_analysis?.custom_analysis_data?.service_requested || '',
  lead_score: gptData.lead_score ?? originalData.call_analysis?.custom_analysis_data?.lead_score ?? 0,
  is_hot_lead: gptData.is_hot_lead ?? originalData.call_analysis?.custom_analysis_data?.is_hot_lead ?? false,
  is_lead: gptData.is_lead ?? (gptData.lead_score > 3) ?? false,
  booking_attempted: gptData.booking_attempted ?? originalData.call_analysis?.custom_analysis_data?.booking_attempted ?? false,
  booking_success: gptData.booking_success ?? originalData.call_analysis?.custom_analysis_data?.booking_success ?? false,
  appointment_date: gptData.appointment_date || originalData.call_analysis?.custom_analysis_data?.appointment_date || null,
  appointment_time_window: gptData.appointment_time_window || originalData.call_analysis?.custom_analysis_data?.appointment_time_window || '',
  job_type_booked: gptData.job_type_booked || originalData.call_analysis?.custom_analysis_data?.job_type_booked || '',
  reschedule_or_cancel: gptData.reschedule_or_cancel || 'neither',
  vulnerable_occupant: gptData.vulnerable_occupant || false,
  transfer_attempted: gptData.transfer_attempted || false,
  transfer_success: gptData.transfer_success ?? null,
  summary: gptData.summary || originalData.call_analysis?.call_summary || '',
  notes: gptData.notes || '',
  notification_type: '',
  notification_priority: gptData.lead_score >= 8 ? 'high' : gptData.lead_score >= 5 ? 'normal' : 'low',
};

return [{ json: merged }];

